INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("魔法防御力（ダウン不可）アップ", "boss_magic_def_lower_limit", 4100210, 10021004, "バトル開始時、すべてのモンスターの魔法防御力を特大アップさせる。この効果は魔法防御力ダウンの影響を受けない。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＴＰダウンカット", "boss_tp_down_cut", 4100210, 10021005, "バトル開始時、すべてのモンスターがＴＰダウン\n100％カット状態になる。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＴＰ上昇ダウン", 3, 4100210, 10021006, "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＨＰ吸収ダウン", 9, 4100210, 10021007, "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。");
